const { Pool } = require('pg');

async function query({ sql, params = [], connectionString }) {
  const pool = new Pool({ connectionString: connectionString || process.env.DATABASE_URL });
  try {
    const result = await pool.query(sql, params);
    return { rows: result.rows, rowCount: result.rowCount, fields: result.fields.map(f => f.name) };
  } finally {
    await pool.end();
  }
}

module.exports = { query };
